import 'package:flutter/material.dart';
import 'package:uni_links/uni_links.dart';
import 'package:url_launcher/url_launcher.dart';

class DeepLinkHandler extends StatefulWidget {
  final Widget child;
  
  DeepLinkHandler({required this.child});

  @override
  _DeepLinkHandlerState createState() => _DeepLinkHandlerState();
}

class _DeepLinkHandlerState extends State<DeepLinkHandler> {
  String? _initialLink;
  final StreamSubscription<String?> _sub = getUriLinksStream().listen((String? uri) {
    if (uri != null) {
      _handleDeepLink(uri);
    }
  });

  @override
  void initState() {
    super.initState();
    _initUniLinks();
  }

  Future<void> _initUniLinks() async {
    try {
      final initialLink = await getInitialUri();
      if (initialLink != null) {
        _handleDeepLink(initialLink.toString());
      }
    } catch (e) {
      print('Error getting initial link: $e');
    }
  }

  void _handleDeepLink(String uri) {
    final Uri parsedUri = Uri.parse(uri);
    final path = parsedUri.path;
    final segments = path.split('/').where((s) => s.isNotEmpty).toList();
    
    if (segments.isEmpty) return;

    final route = segments[0];
    final id = segments.length > 1 ? segments[1] : null;

    WidgetsBinding.instance.addPostFrameCallback((_) {
      _navigateToRoute(route, id);
    });
  }

  void _navigateToRoute(String route, String? id) {
    final navigator = Navigator.of(context);
    
    switch (route) {
      case 'profile':
        if (id != null) {
          navigator.pushNamed('/profile', arguments: {'id': id});
        }
        break;
      case 'payment':
        if (id != null && id == 'confirm') {
          navigator.pushNamed('/payment/confirm');
        }
        break;
      default:
        print('Unknown route: $route');
    }
  }

  @override
  Widget build(BuildContext context) {
    return widget.child;
  }

  @override
  void dispose() {
    _sub.cancel();
    super.dispose();
  }
}

class AppRouter {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    switch (settings.name) {
      case '/profile':
        final args = settings.arguments as Map<String, dynamic>;
        return MaterialPageRoute(
          builder: (_) => ProfileScreen(userId: args['id']),
        );
      case '/payment/confirm':
        return MaterialPageRoute(
          builder: (_) => PaymentConfirmationScreen(),
        );
      default:
        return MaterialPageRoute(
          builder: (_) => Scaffold(
            appBar: AppBar(title: Text('Not Found')),
            body: Center(child: Text('Route not found')),
          ),
        );
    }
  }
}

